import React, { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import { formatDistanceToNow } from 'date-fns';
import './Dashboard.css';

const URGENCY_BADGE = { critical: 'badge-red', high: 'badge-orange', medium: 'badge-yellow', low: 'badge-green' };
const STATUS_BADGE  = { open: 'badge-blue', 'in-progress': 'badge-orange', closed: 'badge-gray' };

export default function Dashboard() {
  const { user } = useAuth();
  const [data, setData] = useState({ activeRequests: [], availableDonors: [], recentDonations: [], unreadCount: 0 });
  const [loading, setLoading] = useState(true);
  const [lastUpdated, setLastUpdated] = useState(null);

  const fetchDashboard = useCallback(async () => {
    try {
      const res = await api.get('/dashboard');
      setData(res.data);
      setLastUpdated(new Date());
    } catch {}
    finally { setLoading(false); }
  }, []);

  useEffect(() => {
    fetchDashboard();
    const interval = setInterval(fetchDashboard, 10000);
    return () => clearInterval(interval);
  }, [fetchDashboard]);

  if (loading) return (
    <div className="page-container" style={{ textAlign: 'center', paddingTop: '4rem' }}>
      <span className="spinner" style={{ width: 36, height: 36 }} />
    </div>
  );

  return (
    <div className="page-container">
      <div className="dashboard-header">
        <div>
          <h1 className="page-title" style={{ marginBottom: 4 }}>Welcome, {user?.name} 👋</h1>
          <p className="dashboard-subtitle">
            {lastUpdated && `Last updated ${formatDistanceToNow(lastUpdated, { addSuffix: true })}`}
            <button className="refresh-btn" onClick={fetchDashboard}>↻ Refresh</button>
          </p>
        </div>
        <div className="dashboard-actions">
          <Link to="/request" className="btn btn-primary">+ Emergency Request</Link>
          {(user?.role === 'donor') && <Link to="/register-donor" className="btn btn-outline">Register as Donor</Link>}
        </div>
      </div>

      {/* Stats row */}
      <div className="stats-row">
        <div className="stat-card card">
          <span className="stat-icon">🚨</span>
          <div>
            <div className="stat-value">{data.activeRequests.length}</div>
            <div className="stat-label">Active Requests</div>
          </div>
        </div>
        <div className="stat-card card">
          <span className="stat-icon">🩸</span>
          <div>
            <div className="stat-value">{data.availableDonors.length}</div>
            <div className="stat-label">Available Donors</div>
          </div>
        </div>
        <div className="stat-card card">
          <span className="stat-icon">✅</span>
          <div>
            <div className="stat-value">{data.recentDonations.length}</div>
            <div className="stat-label">Recent Donations</div>
          </div>
        </div>
        <div className="stat-card card">
          <span className="stat-icon">🔔</span>
          <div>
            <div className="stat-value">{data.unreadCount}</div>
            <div className="stat-label">Unread Alerts</div>
          </div>
        </div>
      </div>

      <div className="grid-2">
        {/* Active Requests */}
        <div className="card">
          <h2 className="section-title">🚨 Active Blood Requests</h2>
          {data.activeRequests.length === 0
            ? <p className="empty-msg">No active requests right now.</p>
            : data.activeRequests.map(req => (
              <div key={req.id} className="request-item">
                <div className="request-top">
                  <span className="blood-group-badge">{req.blood_group}</span>
                  <span className={`badge ${URGENCY_BADGE[req.urgency] || 'badge-gray'}`}>{req.urgency}</span>
                  <span className={`badge ${STATUS_BADGE[req.status] || 'badge-gray'}`}>{req.status}</span>
                </div>
                <div className="request-info">
                  <strong>{req.patient_name}</strong> · {req.units_needed} unit(s)
                </div>
                <div className="request-meta">
                  🏥 {req.hospital_name} · 📍 {req.location}
                </div>
                <div className="request-footer">
                  <span className="time-ago">{formatDistanceToNow(new Date(req.created_at), { addSuffix: true })}</span>
                  <Link to={`/matched/${req.id}`} className="btn btn-secondary btn-xs">View Donors</Link>
                </div>
              </div>
            ))
          }
        </div>

        {/* Available Donors */}
        <div className="card">
          <h2 className="section-title">🩸 Available Donors</h2>
          {data.availableDonors.length === 0
            ? <p className="empty-msg">No donors registered yet.</p>
            : data.availableDonors.map(d => (
              <div key={d.id} className="donor-item">
                <span className="blood-group-badge">{d.blood_group}</span>
                <div className="donor-info">
                  <strong>{d.name}</strong>
                  <span className="donor-meta">📍 {d.location || 'Location not set'} · 📞 {d.phone || 'N/A'}</span>
                </div>
                <span className="badge badge-green">Available</span>
              </div>
            ))
          }
        </div>
      </div>

      {/* Recent Donations */}
      {data.recentDonations.length > 0 && (
        <div className="card" style={{ marginTop: '1.5rem' }}>
          <h2 className="section-title">✅ Recent Donations</h2>
          <div className="donations-list">
            {data.recentDonations.map(d => (
              <div key={d.id} className="donation-item">
                <span className="blood-group-badge">{d.blood_group}</span>
                <span><strong>{d.donor_name}</strong> donated for request at <strong>{d.hospital_name}</strong></span>
                <span className="time-ago">{formatDistanceToNow(new Date(d.responded_at), { addSuffix: true })}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
